package com.example.mfa.service;

import com.example.mfa.domain.AppUser;
import com.example.mfa.domain.BackupCode;
import com.example.mfa.repo.BackupCodeRepository;
import com.example.mfa.repo.UserRepository;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.security.SecureRandom;
import java.time.Instant;
import java.util.ArrayList;
import java.util.Base64;
import java.util.List;
import java.util.Locale;
import java.util.UUID;
import java.util.stream.Collectors;

@Service
class BackupCodeService {
    private final UserRepository userRepository;
    private final BackupCodeRepository backupCodeRepository;
    private final PasswordEncoder passwordEncoder;
    private final SecureRandom secureRandom = new SecureRandom();

    BackupCodeService(UserRepository userRepository, BackupCodeRepository backupCodeRepository, PasswordEncoder passwordEncoder) {
        this.userRepository = userRepository;
        this.backupCodeRepository = backupCodeRepository;
        this.passwordEncoder = passwordEncoder;
    }

    @Transactional
    public List<String> generateAndStoreCodes(Long userId, int count) {
        AppUser user = userRepository.findById(userId).orElseThrow(() -> new IllegalArgumentException("User not found"));
        List<String> plainCodes = new ArrayList<>();
        List<BackupCode> entities = new ArrayList<>();
        for (int i = 0; i < count; i++) {
            String plain = createHumanFriendlyCode();
            plainCodes.add(plain);
            BackupCode code = new BackupCode();
            code.setUser(user);
            code.setCodeHash(passwordEncoder.encode(plain));
            code.setUsed(false);
            entities.add(code);
        }
        backupCodeRepository.saveAll(entities);
        return plainCodes;
    }

    @Transactional
    public boolean verifyAndConsumeCode(Long userId, String code) {
        List<BackupCode> codes = backupCodeRepository.findByUserIdAndUsedFalse(userId);
        for (BackupCode backupCode : codes) {
            if (passwordEncoder.matches(code, backupCode.getCodeHash())) {
                backupCode.setUsed(true);
                backupCode.setUsedAt(Instant.now());
                backupCodeRepository.save(backupCode);
                return true;
            }
        }
        return false;
    }

    @Transactional(readOnly = true)
    public List<String> getRemainingUnusedCodeHashes(Long userId) {
        return backupCodeRepository.findByUserIdAndUsedFalse(userId).stream()
                .map(BackupCode::getCodeHash)
                .collect(Collectors.toList());
    }

    private String createHumanFriendlyCode() {
        byte[] bytes = new byte[9];
        secureRandom.nextBytes(bytes);
        String raw = Base64.getUrlEncoder().withoutPadding().encodeToString(bytes).toUpperCase(Locale.ROOT);
        return raw.substring(0, 4) + "-" + raw.substring(4, 8) + "-" + raw.substring(8, 12);
    }
}

package com.example.mfa.service;

import com.example.mfa.domain.AppUser;
import com.example.mfa.repo.UserRepository;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
class UserService {
    private final UserRepository userRepository;
    private final PasswordEncoder passwordEncoder;
    private final BackupCodeService backupCodeService;

    UserService(UserRepository userRepository, PasswordEncoder passwordEncoder, BackupCodeService backupCodeService) {
        this.userRepository = userRepository;
        this.passwordEncoder = passwordEncoder;
        this.backupCodeService = backupCodeService;
    }

    @Transactional
    public AppUser register(String username, String password) {
        if (userRepository.existsByUsername(username)) {
            throw new IllegalArgumentException("Username already exists");
        }
        AppUser user = new AppUser();
        user.setUsername(username);
        user.setPasswordHash(passwordEncoder.encode(password));
        return userRepository.save(user);
    }

    @Transactional
    public List<String> enableMfaAndGenerateBackupCodes(Long userId, String mfaSecret) {
        AppUser user = userRepository.findById(userId).orElseThrow(() -> new IllegalArgumentException("User not found"));
        user.setMfaSecret(mfaSecret);
        user.setTwoFactorEnabled(true);
        userRepository.save(user);
        return backupCodeService.generateAndStoreCodes(userId, 10);
    }
}

package com.example.mfa.service;

import com.example.mfa.domain.AppUser;
import com.example.mfa.repo.UserRepository;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
class AuthenticationService {
    private final UserRepository userRepository;
    private final PasswordEncoder passwordEncoder;
    private final BackupCodeService backupCodeService;

    AuthenticationService(UserRepository userRepository, PasswordEncoder passwordEncoder, BackupCodeService backupCodeService) {
        this.userRepository = userRepository;
        this.passwordEncoder = passwordEncoder;
        this.backupCodeService = backupCodeService;
    }

    @Transactional(readOnly = true)
    public boolean authenticatePassword(String username, String password) {
        AppUser user = userRepository.findByUsername(username).orElseThrow(() -> new IllegalArgumentException("Invalid credentials"));
        return passwordEncoder.matches(password, user.getPasswordHash());
    }

    @Transactional
    public boolean authenticateWithBackupCode(String username, String backupCode) {
        AppUser user = userRepository.findByUsername(username).orElseThrow(() -> new IllegalArgumentException("Invalid credentials"));
        if (!user.isTwoFactorEnabled()) {
            throw new IllegalStateException("MFA not enabled");
        }
        return backupCodeService.verifyAndConsumeCode(user.getId(), backupCode);
    }
}

package com.example.mfa.web;

import com.example.mfa.domain.AppUser;
import com.example.mfa.service.AuthenticationService;
import com.example.mfa.service.UserService;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.List;

@RestController
@RequestMapping("/api/auth")
class AuthController {
    private final UserService userService;
    private final AuthenticationService authenticationService;

    AuthController(UserService userService, AuthenticationService authenticationService) {
        this.userService = userService;
        this.authenticationService = authenticationService;
    }

    @PostMapping("/register")
    public ResponseEntity<UserResponse> register(@RequestBody RegisterRequest request) {
        AppUser user = userService.register(request.username(), request.password());
        return ResponseEntity.status(HttpStatus.CREATED).body(new UserResponse(user.getId(), user.getUsername(), user.isTwoFactorEnabled()));
    }

    @PostMapping("/mfa/enable")
    public ResponseEntity<MfaEnableResponse> enableMfa(@RequestBody EnableMfaRequest request) {
        List<String> backupCodes = userService.enableMfaAndGenerateBackupCodes(request.userId(), request.mfaSecret());
        return ResponseEntity.ok(new MfaEnableResponse(request.userId(), backupCodes));
    }

    @PostMapping("/login/password")
    public ResponseEntity<LoginResponse> loginPassword(@RequestBody LoginPasswordRequest request) {
        boolean ok = authenticationService.authenticatePassword(request.username(), request.password());
        return ResponseEntity.ok(new LoginResponse(ok, "PASSWORD_AUTHENTICATED"));
    }

    @PostMapping("/login/backup-code")
    public ResponseEntity<LoginResponse> loginBackupCode(@RequestBody LoginBackupCodeRequest request) {
        boolean ok = authenticationService.authenticateWithBackupCode(request.username(), request.backupCode());
        return ResponseEntity.ok(new LoginResponse(ok, ok ? "BACKUP_CODE_AUTHENTICATED" : "INVALID_BACKUP_CODE"));
    }
}

record RegisterRequest(String username, String password) {}
record EnableMfaRequest(Long userId, String mfaSecret) {}
record LoginPasswordRequest(String username, String password) {}
record LoginBackupCodeRequest(String username, String backupCode) {}
record UserResponse(Long id, String username, boolean twoFactorEnabled) {}
record MfaEnableResponse(Long userId, List<String> backupCodes) {}
record LoginResponse(boolean success, String message) {}

